sql:
SELECT error_type_name, category
FROM error_types
WHERE severity_level > 3;

SELECT instructor_id, COUNT(set_id) AS number_of_assessments
FROM assessment_sets
GROUP BY instructor_id;

SELECT error_type_name, category
FROM error_types
ORDER BY category;

SELECT set_name
FROM assessment_sets
ORDER BY created_date DESC;

SELECT SUM(error_count) AS total_errors
FROM error_counts
WHERE set_id = '0';

SELECT rs.report_type, aset.set_name
FROM reports rs
INNER JOIN assessment_sets aset ON rs.set_id = aset.set_id;

SELECT COUNT(DISTINCT student_id) AS unique_students_with_grade
FROM student_responses
WHERE set_id = '1' AND grade IS NOT NULL;

